contracts/Platform.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.24;

import {IERC20} from "@openzeppelin/contracts/token/ERC20/IERC20.sol";
import {SafeERC20} from "@openzeppelin/contracts/token/ERC20/utils/SafeERC20.sol";
import {Ownable} from "@openzeppelin/contracts/access/Ownable.sol";

interface ITradingBotManager {
    function setTradeExecutor(address executor) external;
    function pause() external;
    function unpause() external;
}

contract Platform is Ownable {
    using SafeERC20 for IERC20;

    IERC20 public traderToken;
    ITradingBotManager public botManager;

    uint256 public subscriptionFee;

    mapping(address => bool) public hasActiveSubscription;

    event SubscriptionPaid(address indexed user, uint256 amount);
    event FeeUpdated(uint256 newFee);
    event AddressesUpdated(address token, address manager);

    error ZeroAddress();

    constructor(
        address _traderToken, 
        address _botManager,
        uint256 _subscriptionFee
    ) Ownable(msg.sender) {
        if (_traderToken == address(0) || _botManager == address(0)) revert ZeroAddress();
        traderToken = IERC20(_traderToken);
        botManager = ITradingBotManager(_botManager);
        subscriptionFee = _subscriptionFee;
    }

    function setAddresses(address _traderToken, address _botManager) external onlyOwner {
        if (_traderToken == address(0) || _botManager == address(0)) revert ZeroAddress();
        traderToken = IERC20(_traderToken);
        botManager = ITradingBotManager(_botManager);
        emit AddressesUpdated(_traderToken, _botManager);
    }

    function setSubscriptionFee(uint256 _fee) external onlyOwner {
        subscriptionFee = _fee;
        emit FeeUpdated(_fee);
    }

    function paySubscription() external {
        if (subscriptionFee > 0) {
            traderToken.safeTransferFrom(msg.sender, address(this), subscriptionFee);
        }

        hasActiveSubscription[msg.sender] = true;

        emit SubscriptionPaid(msg.sender, subscriptionFee);
    }

    // --- Bot Manager Orchestration Controls ---

    function updateBotManagerExecutor(address _newExecutor) external onlyOwner {
        botManager.setTradeExecutor(_newExecutor);
    }

    function pauseBotManager() external onlyOwner {
        botManager.pause();
    }

    function unpauseBotManager() external onlyOwner {
        botManager.unpause();
    }

    // --- Collected Fees Withdrawal ---

    function withdrawFees() external onlyOwner {
        uint256 balance = traderToken.balanceOf(address(this));
        if (balance > 0) {
            traderToken.safeTransfer(owner(), balance);
        }
    }
}

contracts/TradeExecutor.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.24;

import {AggregatorV3Interface} from "@chainlink/contracts/src/v0.8/shared/interfaces/AggregatorV3Interface.sol";
import {Ownable} from "@openzeppelin/contracts/access/Ownable.sol";

// Minimal interface for interaction with the Vault
interface ITradingBotManager {
    function debitBot(uint256 botId, uint256 amount) external;
    function creditBot(uint256 botId) external payable;
    function bots(uint256 botId) external view returns (address owner, string memory configCid, uint96 balance, bool active);
}

contract TradeExecutor is Ownable {
    ITradingBotManager public botManager;
    AggregatorV3Interface public priceFeed;

    uint256 public rewardPercentage = 5;
    uint256 public lossPercentage = 5;

    event TradeExecuted(uint256 indexed botId, int256 currentPrice, bool isWin, uint256 impactAmount);
    event AddressesUpdated(address botManager, address priceFeed);

    error InvalidBot();
    error ZeroAddress();
    error InvalidPrice();
    error InsufficientExecutorBalance();

    constructor(
        address _botManager,
        address _priceFeed
    ) Ownable(msg.sender) {
        if (_botManager == address(0) || _priceFeed == address(0)) revert ZeroAddress();
        botManager = ITradingBotManager(_botManager);
        priceFeed = AggregatorV3Interface(_priceFeed);
    }

    function setAddresses(address _botManager, address _priceFeed) external onlyOwner {
        if (_botManager == address(0) || _priceFeed == address(0)) revert ZeroAddress();
        botManager = ITradingBotManager(_botManager);
        priceFeed = AggregatorV3Interface(_priceFeed);
        emit AddressesUpdated(_botManager, _priceFeed);
    }

    /**
     * @dev Fetches the latest price from the oracle data provider (Chainlink ETH/USD)
     */
    function getLatestPrice() public view returns (int256) {
        (
            /* uint80 roundID */,
            int256 price,
            /* uint startedAt */,
            /* uint timeStamp */,
            /* uint80 answeredInRound */
        ) = priceFeed.latestRoundData();
        return price;
    }

    /**
     * @dev Simulates a trade execution using market data.
     * @param botId The ID of the bot executing the trade.
     * @param tradeAmount Position size (risked balance).
     * @param direction Trade direction: true = LONG, false = SHORT.
     * @param referencePrice The market price when the bot entered the trade.
     */
    function executeSimulatedTrade(
        uint256 botId, 
        uint256 tradeAmount, 
        bool direction, 
        int256 referencePrice
    ) external onlyOwner {
        (, , uint96 balance, bool active) = botManager.bots(botId);
        if (!active || balance < tradeAmount || tradeAmount == 0) revert InvalidBot();

        int256 currentPrice = getLatestPrice();
        if (currentPrice <= 0) revert InvalidPrice();

        // Market logic: LONG (true) wins if Current Price > Entry Price, SHORT (false) wins otherwise
        bool isWin = direction ? (currentPrice > referencePrice) : (currentPrice < referencePrice);

        if (isWin) {
            uint256 profit = (tradeAmount * rewardPercentage) / 100;

            // The executor must have enough ETH to pay profits
            if (address(this).balance < profit) revert InsufficientExecutorBalance();

            botManager.creditBot{value: profit}(botId);

            emit TradeExecuted(botId, currentPrice, true, profit);
        } else {
            uint256 loss = (tradeAmount * lossPercentage) / 100;

            botManager.debitBot(botId, loss);

            emit TradeExecuted(botId, currentPrice, false, loss);
        }
    }

    /**
     * @dev Allows liquidity injection into the executor to pay for winnings.
     */
    receive() external payable {}

    /**
     * @dev Allows the Owner to withdraw liquidity from the executor pool if necessary.
     */
    function withdrawLiquidity(uint256 amount) external onlyOwner {
        require(address(this).balance >= amount, "Insufficient balance");
        payable(owner()).transfer(amount);
    }
}

contracts/TradingBotManager.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.24;

contract TradingBotManager {

    struct Bot {
        address owner;
        string configCid;
        uint96 balance;
        bool active;
    }

    uint256 public botCount;

    mapping(uint256 => Bot) public bots;

    mapping(address => uint256[]) private userBots;

    bool public paused;

    address public owner;

    address public tradeExecutor;

    uint256 public totalFunds;

    uint256 private constant NOT_ENTERED = 1;
    uint256 private constant ENTERED = 2;

    uint256 private status = NOT_ENTERED;

    event BotCreated(uint256 indexed botId, address indexed owner);
    event BotDeactivated(uint256 indexed botId);

    event Deposited(
        uint256 indexed botId,
        address indexed owner,
        uint256 amount,
        uint256 newBalance
    );

    event Withdrawn(
        uint256 indexed botId,
        address indexed receiver,
        uint256 amount
    );

    event EmergencyWithdraw(
        uint256 indexed botId,
        address indexed owner,
        uint256 amount
    );

    event BotDebited(uint256 indexed botId, uint256 amount);
    event BotCredited(uint256 indexed botId, uint256 amount);

    event OwnershipTransferred(address indexed oldOwner, address indexed newOwner);
    event TradeExecutorUpdated(address indexed executor);

    event Paused();
    event Unpaused();

    error BotDoesNotExist();
    error Unauthorized();
    error OwnerOnly();
    error InvalidAmount();
    error BotInactive();
    error BotAlreadyInactive();
    error TransferFailed();
    error Reentrancy();
    error ContractPaused();
    error ExecutorNotSet();
    error BalanceOverflow();
    error Insolvent();

    constructor() {
        owner = msg.sender;
    }

    modifier onlyOwner() {
        if (msg.sender != owner) revert OwnerOnly();
        _;
    }

    modifier onlyExecutor() {
        if (tradeExecutor == address(0)) revert ExecutorNotSet();
        if (msg.sender != tradeExecutor) revert Unauthorized();
        _;
    }

    modifier botExists(uint256 botId) {
        if (botId >= botCount) revert BotDoesNotExist();
        _;
    }

    modifier onlyBotOwner(uint256 botId) {
        if (bots[botId].owner != msg.sender) revert Unauthorized();
        _;
    }

    modifier botActive(uint256 botId) {
        if (!bots[botId].active) revert BotInactive();
        _;
    }

    modifier nonReentrant() {
        if (status == ENTERED) revert Reentrancy();
        status = ENTERED;
        _;
        status = NOT_ENTERED;
    }

    modifier whenNotPaused() {
        if (paused) revert ContractPaused();
        _;
    }

    function transferOwnership(address newOwner) external onlyOwner {
        if (newOwner == address(0)) revert Unauthorized();

        address oldOwner = owner;
        owner = newOwner;

        emit OwnershipTransferred(oldOwner, newOwner);
    }

    function setTradeExecutor(address executor) external onlyOwner {
        if (executor == address(0)) revert Unauthorized();

        tradeExecutor = executor;

        emit TradeExecutorUpdated(executor);
    }

    function createBot(string calldata cid)
        external
        whenNotPaused
        returns (uint256 botId)
    {
        botId = botCount;

        bots[botId] = Bot({
            owner: msg.sender,
            configCid: cid,
            balance: 0,
            active: true
        });

        userBots[msg.sender].push(botId);

        emit BotCreated(botId, msg.sender);

        unchecked {
            botCount++;
        }
    }

    function deactivateBot(uint256 botId)
        external
        whenNotPaused
        botExists(botId)
        onlyBotOwner(botId)
    {
        Bot storage bot = bots[botId];

        if (!bot.active) revert BotAlreadyInactive();
        if (bot.balance != 0) revert InvalidAmount();

        bot.active = false;

        emit BotDeactivated(botId);
    }

    function deposit(uint256 botId)
        external
        payable
        whenNotPaused
        botExists(botId)
        onlyBotOwner(botId)
        botActive(botId)
    {
        uint256 amount = msg.value;

        if (amount == 0) revert InvalidAmount();

        Bot storage bot = bots[botId];

        uint256 newBalance = bot.balance + amount;

        if (newBalance > type(uint96).max) revert BalanceOverflow();

        bot.balance = uint96(newBalance);

        totalFunds += amount;

        emit Deposited(botId, msg.sender, amount, newBalance);
    }

    function withdraw(uint256 botId)
        external
        botExists(botId)
        onlyBotOwner(botId)
        nonReentrant
    {
        Bot storage bot = bots[botId];

        uint256 amount = bot.balance;

        if (amount == 0) revert InvalidAmount();

        bot.balance = 0;

        totalFunds -= amount;

        (bool success,) = payable(msg.sender).call{value: amount}("");

        if (!success) revert TransferFailed();

        emit Withdrawn(botId, msg.sender, amount);
    }

    function withdrawTo(uint256 botId, address to)
        external
        botExists(botId)
        onlyBotOwner(botId)
        nonReentrant
    {
        if (to == address(0)) revert Unauthorized();

        Bot storage bot = bots[botId];

        uint256 amount = bot.balance;

        if (amount == 0) revert InvalidAmount();

        bot.balance = 0;

        totalFunds -= amount;

        (bool success,) = payable(to).call{value: amount}("");

        if (!success) revert TransferFailed();

        emit Withdrawn(botId, to, amount);
    }

    function emergencyWithdraw(uint256 botId)
        external
        botExists(botId)
        onlyBotOwner(botId)
        nonReentrant
    {
        Bot storage bot = bots[botId];

        uint256 amount = bot.balance;

        if (amount == 0) revert InvalidAmount();

        bot.balance = 0;
        bot.active = false;

        totalFunds -= amount;

        (bool success,) = payable(msg.sender).call{value: amount}("");

        if (!success) revert TransferFailed();

        emit EmergencyWithdraw(botId, msg.sender, amount);
    }

    function debitBot(uint256 botId, uint256 amount)
        external
        onlyExecutor
        botExists(botId)
    {
        Bot storage bot = bots[botId];

        if (!bot.active) revert BotInactive();
        if (bot.balance < amount) revert InvalidAmount();

        bot.balance -= uint96(amount);

        totalFunds -= amount;

        emit BotDebited(botId, amount);
    }

    function creditBot(uint256 botId)
        external
        payable
        onlyExecutor
        botExists(botId)
    {
        uint256 amount = msg.value;

        if (amount == 0) revert InvalidAmount();

        Bot storage bot = bots[botId];

        uint256 newBalance = bot.balance + amount;

        if (newBalance > type(uint96).max) revert BalanceOverflow();

        bot.balance = uint96(newBalance);

        totalFunds += amount;

        emit BotCredited(botId, amount);
    }

    function pause() external onlyOwner {
        paused = true;
        emit Paused();
    }

    function unpause() external onlyOwner {
        paused = false;
        emit Unpaused();
    }

    function getUserBots(address user)
        external
        view
        returns (uint256[] memory)
    {
        return userBots[user];
    }

    function isSolvent() external view returns (bool) {
        return address(this).balance >= totalFunds;
    }

    receive() external payable {
        revert();
    }
}

